/**
 * zsh 集成脚本模板。
 * 通过 ZLE widget 绑定 Ctrl+G，把用户意图和当前 BUFFER 交给
 * `wts generate --inline`，用返回的命令替换 BUFFER 但不执行。
 *
 * 实现细节说明：脚本内容以纯字符串拼接方式构造，避免与 JS 模板插值冲突。
 */
const LINES: string[] = [
  '# >>> WhatTheShell (wts) zsh integration >>>',
  '# Generated by: wts shell-init zsh',
  '# 安装: 在 ~/.zshrc 里加入:    eval "$(wts shell-init zsh)"',
  '',
  '__wts_inline_widget() {',
  '  emulate -L zsh',
  '  local current="$BUFFER"',
  '  local intent=""',
  '',
  '  print',
  '  if ! IFS= read -r "intent?wts > "; then',
  '    zle reset-prompt',
  '    return 0',
  '  fi',
  '  if [[ -z "$intent" ]]; then',
  '    zle reset-prompt',
  '    return 0',
  '  fi',
  '',
  '  print -n $\'\\e[2Kwts: thinking...\\r\'',
  '',
  '  local tmpout tmperr rc',
  '  tmpout=$(mktemp 2>/dev/null) || { zle reset-prompt; return 1 }',
  '  tmperr=$(mktemp 2>/dev/null) || { rm -f "$tmpout"; zle reset-prompt; return 1 }',
  '',
  '  command wts generate --inline \\',
  '    --buffer "$current" \\',
  '    --history-file "${HISTFILE:-}" \\',
  '    -- "$intent" \\',
  '    >"$tmpout" 2>"$tmperr"',
  '  rc=$?',
  '',
  '  print -n $\'\\e[2K\\r\'',
  '',
  '  if (( rc == 0 )); then',
  '    BUFFER=$(<"$tmpout")',
  '    CURSOR=${#BUFFER}',
  '  else',
  '    print -r -- "$(<"$tmperr")" >&2',
  '    BUFFER="$current"',
  '    CURSOR=${#BUFFER}',
  '  fi',
  '',
  '  rm -f "$tmpout" "$tmperr"',
  '  zle reset-prompt',
  '}',
  '',
  'zle -N __wts_inline_widget',
  "bindkey '^G' __wts_inline_widget",
  '# <<< WhatTheShell (wts) zsh integration <<<',
  '',
];

export const ZSH_INIT_SCRIPT = LINES.join('\n');
